agent.js.content:
import { runWithBackpressure } from "../lib/backpressure.js";
import { detectAddress } from "../utils/address.js";
import { safeReply } from "../utils/telegram.js";
import { analyzeScan, analyzeWallet } from "../services/intel.js";

function includesSecret(text) {
  const t = String(text || "").toLowerCase();
  return t.includes("seed phrase") || t.includes("private key") || /\b([a-z]+\s+){11,23}[a-z]+\b/.test(t);
}

function shouldReplyInGroup(ctx, raw) {
  const type = ctx.chat?.type || "private";
  if (type === "private") return true;

  const username = ctx.me?.username || ctx.botInfo?.username || "";
  const reply = ctx.message?.reply_to_message;
  const replyToBot = Boolean(reply?.from?.is_bot && username && String(reply.from.username || "").toLowerCase() === username.toLowerCase());
  const mentioned = username && String(raw).toLowerCase().includes(`@${username.toLowerCase()}`);
  return Boolean(replyToBot || mentioned);
}

export function registerAgent(bot) {
  bot.on("message:text", async (ctx, next) => {
    const raw = ctx.message?.text || "";
    if (raw.startsWith("/")) return next();
    if (!shouldReplyInGroup(ctx, raw)) return next();

    const username = ctx.me?.username || ctx.botInfo?.username || "";
    const text = username ? raw.replace(new RegExp(`@${username}\\b`, "ig"), "").trim() : raw.trim();
    if (!text) return safeReply(ctx, "Send a contract, wallet, or command like /scan, /price, /news, or /help.");

    if (includesSecret(text)) {
      return safeReply(ctx, "Never share seed phrases or private keys. I cannot process secrets. If you posted one, move funds to a fresh wallet immediately.");
    }

    const detected = detectAddress(text);
    if (detected.type === "evm") {
      return runWithBackpressure(ctx, async () => {
        await safeReply(ctx, "Detected a likely EVM contract or wallet address. Running a security-oriented scan now.");
        await safeReply(ctx, await analyzeScan(detected.address));
      });
    }

    if (detected.type === "solana") {
      return runWithBackpressure(ctx, async () => {
        await safeReply(ctx, "Detected a likely Solana wallet address. Running a public wallet summary now.");
        await safeReply(ctx, await analyzeWallet(detected.address));
      });
    }

    return safeReply(ctx, "I can analyze crypto assets with /scan, /price, /nft, /wallet, /news, and /sentiment. Paste a contract or wallet address and I’ll route it automatically.");
  });
}

index.js.content:
import "dotenv/config";
import { run } from "@grammyjs/runner";
import { cfg } from "./lib/config.js";
import { log, safeErr } from "./lib/logger.js";

process.on("unhandledRejection", (reason) => {
  log.error("process.unhandledRejection", { err: safeErr(reason) });
  process.exit(1);
});

process.on("uncaughtException", (err) => {
  log.error("process.uncaughtException", { err: safeErr(err) });
  process.exit(1);
});

function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

async function boot() {
  log.info("boot.start", {
    platform: "telegram",
    telegramTokenSet: Boolean(cfg.TELEGRAM_BOT_TOKEN),
    aiEndpointSet: Boolean(cfg.COOKMYBOTS_AI_ENDPOINT),
    aiKeySet: Boolean(cfg.COOKMYBOTS_AI_KEY),
    openSeaKeySet: Boolean(cfg.OPENSEA_API_KEY)
  });

  if (!cfg.TELEGRAM_BOT_TOKEN) {
    console.error("TELEGRAM_BOT_TOKEN is required. Add it in your environment and redeploy.");
    process.exit(1);
  }

  try {
    const { createBot } = await import("./bot.js");
    const bot = await createBot(cfg.TELEGRAM_BOT_TOKEN);

    await bot.init();

    await bot.api.setMyCommands([
      { command: "start", description: "Welcome and supported chains" },
      { command: "help", description: "Show command examples" },
      { command: "scan", description: "Token security scan" },
      { command: "price", description: "Market and price analysis" },
      { command: "nft", description: "NFT collection intelligence" },
      { command: "wallet", description: "Public wallet summary" },
      { command: "news", description: "Latest crypto news" },
      { command: "sentiment", description: "Token sentiment analysis" },
      { command: "about", description: "Capabilities and limitations" }
    ]);

    log.info("telegram.webhook.clear.start", { dropPendingUpdates: true });
    await bot.api.deleteWebhook({ drop_pending_updates: true });

    let lastMemLog = 0;
    const memTimer = setInterval(() => {
      const now = Date.now();
      if (now - lastMemLog < 60_000) return;
      lastMemLog = now;
      const m = process.memoryUsage();
      log.info("mem", {
        rssMB: Math.round(m.rss / 1e6),
        heapUsedMB: Math.round(m.heapUsed / 1e6)
      });
    }, 60_000);
    memTimer.unref?.();

    let backoffMs = 2_000;

    while (true) {
      let runner = null;
      try {
        log.info("telegram.polling.start", { concurrency: 1 });
        runner = run(bot, {
          sink: { concurrency: 1 },
          runner: {
            fetch: {
              allowed_updates: ["message"]
            }
          }
        });

        await runner.task();
        log.warn("telegram.polling.stopped", {});
        backoffMs = 2_000;
      } catch (err) {
        const msg = safeErr(err);
        const isConflict = msg.includes("409") || msg.toLowerCase().includes("conflict");
        const isRateLimit = msg.includes("429") || msg.toLowerCase().includes("too many requests");
        const isTimeout = msg.toLowerCase().includes("timeout") || msg.toLowerCase().includes("etimedout");

        log.error("telegram.polling.failure", {
          err: msg,
          conflict: isConflict,
          rateLimit: isRateLimit,
          timeout: isTimeout,
          retryInMs: backoffMs
        });

        try {
          await runner?.stop?.();
        } catch (stopErr) {
          log.warn("telegram.polling.stop.failure", { err: safeErr(stopErr) });
        }

        await sleep(backoffMs);
        backoffMs = Math.min(backoffMs === 2_000 ? 5_000 : backoffMs * 2, 20_000);
      }
    }
  } catch (err) {
    log.error("boot.failure", { err: safeErr(err), code: err?.code || "" });
    if (err?.code === "ERR_MODULE_NOT_FOUND") {
      console.error("Check that all relative imports include .js and all files exist under src/.");
    }
    process.exit(1);
  }
}

boot();

ai.js.content:
import { cfg } from "./config.js";
import { createBotProfile } from "./botProfile.js";
import { log, safeErr } from "./logger.js";

function trimSlash(value) {
  return String(value || "").replace(/\/+$/, "");
}

function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

async function readJson(response) {
  const text = await response.text();
  try {
    return { text, json: JSON.parse(text) };
  } catch {
    return { text, json: null };
  }
}

function withTimeout(ms) {
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), ms);
  return { controller, clear: () => clearTimeout(timer) };
}

function isRetryable(status) {
  return status === 408 || status === 429 || status === 500 || status === 502 || status === 503 || status === 504;
}

export async function aiChat({ feature, messages = [], meta = {}, timeoutMs = cfg.AI_TIMEOUT_MS } = {}) {
  const base = trimSlash(cfg.COOKMYBOTS_AI_ENDPOINT);
  const key = cfg.COOKMYBOTS_AI_KEY;

  log.info("ai.chat.start", {
    platform: "telegram",
    feature,
    endpointSet: Boolean(base),
    keySet: Boolean(key)
  });

  if (!base || !key) {
    log.warn("ai.chat.failure", { platform: "telegram", feature, err: "AI gateway not configured" });
    return { ok: false, content: "", error: "AI gateway not configured" };
  }

  const body = {
    messages: [
      { role: "system", content: createBotProfile() },
      ...messages
    ],
    meta: {
      platform: "telegram",
      feature,
      ...meta
    }
  };

  let attempt = 0;
  const maxRetries = Math.max(0, Number(cfg.AI_MAX_RETRIES || 0));

  while (true) {
    attempt += 1;
    const started = Date.now();
    const { controller, clear } = withTimeout(timeoutMs);

    try {
      const response = await fetch(`${base}/chat`, {
        method: "POST",
        headers: {
          Authorization: `Bearer ${key}`,
          "Content-Type": "application/json"
        },
        body: JSON.stringify(body),
        signal: controller.signal
      });

      const { text, json } = await readJson(response);
      const ms = Date.now() - started;

      if (!response.ok) {
        const err = json?.error?.message || json?.message || json?.error || text || `HTTP ${response.status}`;
        log.warn("ai.chat.failure", { platform: "telegram", feature, status: response.status, attempt, ms, err: String(err).slice(0, 500) });
        if (attempt <= maxRetries && isRetryable(response.status)) {
          await sleep(750 * attempt);
          continue;
        }
        return { ok: false, content: "", error: String(err), status: response.status };
      }

      const content = json?.output?.content;
      if (typeof content !== "string" || !content.trim()) {
        const err = "AI response missing output.content";
        log.warn("ai.chat.failure", { platform: "telegram", feature, status: response.status, attempt, ms, err });
        return { ok: false, content: "", error: err, status: response.status };
      }

      log.info("ai.chat.success", { platform: "telegram", feature, status: response.status, attempt, ms });
      return { ok: true, content: content.trim(), status: response.status };
    } catch (err) {
      const msg = err?.name === "AbortError" ? "AI timeout" : safeErr(err);
      log.warn("ai.chat.failure", { platform: "telegram", feature, attempt, timeout: err?.name === "AbortError", err: msg });
      if (attempt <= maxRetries) {
        await sleep(750 * attempt);
        continue;
      }
      return { ok: false, content: "", error: msg };
    } finally {
      clear();
    }
  }
}

export async function aiCryptoNews({ limit = 5 } = {}) {
  const base = trimSlash(cfg.COOKMYBOTS_AI_ENDPOINT);
  const key = cfg.COOKMYBOTS_AI_KEY;
  const safeLimit = Math.max(1, Math.min(Number(limit || 5), 20));

  log.info("ai.news.start", {
    platform: "telegram",
    feature: "news",
    endpointSet: Boolean(base),
    keySet: Boolean(key)
  });

  if (!base || !key) return { ok: false, data: [], error: "AI gateway not configured" };

  const { controller, clear } = withTimeout(cfg.AI_TIMEOUT_MS);
  try {
    const response = await fetch(`${base}/chaingpt/news?limit=${encodeURIComponent(String(safeLimit))}`, {
      headers: { Authorization: `Bearer ${key}` },
      signal: controller.signal
    });
    const { text, json } = await readJson(response);
    if (!response.ok) {
      const err = json?.error?.message || json?.message || json?.error || text || `HTTP ${response.status}`;
      log.warn("ai.news.failure", { platform: "telegram", feature: "news", status: response.status, err: String(err).slice(0, 500) });
      return { ok: false, data: [], error: String(err), status: response.status };
    }
    const data = json?.output?.data || [];
    log.info("ai.news.success", { platform: "telegram", feature: "news", status: response.status, count: Array.isArray(data) ? data.length : 0 });
    return { ok: true, data, status: response.status };
  } catch (err) {
    const msg = err?.name === "AbortError" ? "AI news timeout" : safeErr(err);
    log.warn("ai.news.failure", { platform: "telegram", feature: "news", err: msg });
    return { ok: false, data: [], error: msg };
  } finally {
    clear();
  }
}

export async function synthesize({ feature, language, facts, fallback, instruction }) {
  const prompt = [
    instruction || "Create the final user response from the collected facts.",
    "Keep it under 300 words. Cite only the sources present in the facts. Do not give financial advice.",
    language === "id" ? "Use basic Indonesian." : "Use English.",
    "Facts:",
    JSON.stringify(facts).slice(0, 9000)
  ].join("\n");

  const result = await aiChat({
    feature,
    messages: [
      { role: "user", content: prompt }
    ],
    meta: { language }
  });

  return result.ok && result.content ? result.content.slice(0, 3500) : fallback;
}

backpressure.js.content:
import { cfg } from "./config.js";
import { safeReply } from "../utils/telegram.js";

const chatLocks = new Set();
let globalInFlight = 0;

function keyFor(ctx) {
  return String(ctx.chat?.id || ctx.from?.id || "unknown");
}

export async function runWithBackpressure(ctx, fn) {
  const key = keyFor(ctx);
  const cap = Math.max(1, Number(cfg.GLOBAL_AI_CAP || 1));

  if (chatLocks.has(key)) {
    await safeReply(ctx, "I’m working on your last request. Please wait a moment.");
    return;
  }

  if (globalInFlight >= cap) {
    await safeReply(ctx, "Busy right now. Try again in a moment.");
    return;
  }

  chatLocks.add(key);
  globalInFlight += 1;

  try {
    await fn();
  } finally {
    chatLocks.delete(key);
    globalInFlight = Math.max(0, globalInFlight - 1);
  }
}

