import { postJson } from "../lib/http.js";

export async function getWalletSummary(address, type) {
  const sources = [];
  const notes = [];
  let nativeBalance = null;

  if (type === "solana") {
    const res = await postJson("https://api.mainnet-beta.solana.com", {
      source: "Solana RPC",
      operation: "getBalance",
      body: {
        jsonrpc: "2.0",
        id: 1,
        method: "getBalance",
        params: [address]
      }
    });
    if (res.ok && Number.isFinite(res.data?.result?.value)) {
      nativeBalance = res.data.result.value / 1_000_000_000;
      sources.push("Solana RPC");
    } else {
      notes.push("Solana native balance unavailable from public RPC");
    }
  } else {
    notes.push("EVM token holdings require an indexed wallet data source; no keyed wallet indexer is configured in this no-extra-key build");
  }

  notes.push("NFT portfolio, token USD values, recent transaction pattern, and PnL are limited unless public indexed data is available");

  return {
    address,
    type,
    nativeBalance,
    notes,
    sources
  };
}

address.js.content:
const EVM_RE = /0x[a-fA-F0-9]{40}/;
const SOL_RE = /\b[1-9A-HJ-NP-Za-km-z]{32,44}\b/;

export function firstEvmAddress(text) {
  return String(text || "").match(EVM_RE)?.[0] || "";
}

export function firstSolanaAddress(text) {
  const matches = String(text || "").match(new RegExp(SOL_RE.source, "g")) || [];
  return matches.find((value) => !value.startsWith("0x")) || "";
}

export function detectAddress(text) {
  const evm = firstEvmAddress(text);
  if (evm) return { type: "evm", address: evm, chain: "EVM" };
  const solana = firstSolanaAddress(text);
  if (solana) return { type: "solana", address: solana, chain: "Solana" };
  return { type: "none", address: "", chain: "" };
}

export function isIndonesian(text) {
  const t = String(text || "").toLowerCase();
  return /\b(apa|tolong|harga|dompet|berita|analisa|analisis|risiko|aman|bahaya|kontrak|koin|token|saya|bahasa indonesia|indonesia)\b/.test(t);
}

export function slugifyCollection(name) {
  return String(name || "")
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "");
}

format.js.content:
export function usd(value) {
  const n = Number(value);
  if (!Number.isFinite(n)) return "unavailable";
  if (Math.abs(n) >= 1_000_000_000) return `$${(n / 1_000_000_000).toFixed(2)}B`;
  if (Math.abs(n) >= 1_000_000) return `$${(n / 1_000_000).toFixed(2)}M`;
  if (Math.abs(n) >= 1_000) return `$${(n / 1_000).toFixed(2)}K`;
  if (Math.abs(n) < 0.01 && n !== 0) return `$${n.toPrecision(4)}`;
  return `$${n.toFixed(4)}`;
}

export function pct(value) {
  const n = Number(value);
  if (!Number.isFinite(n)) return "unavailable";
  return `${n >= 0 ? "+" : ""}${n.toFixed(2)}%`;
}

export function short(value, max = 3000) {
  const s = String(value || "").trim();
  return s.length > max ? s.slice(0, max - 1) + "…" : s;
}

export function sourceList(sources) {
  const unique = [...new Set((sources || []).filter(Boolean))];
  return unique.length ? unique.join(", ") : "No live source returned usable data";
}

